from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import json
from pathlib import Path
from typing import Any, Dict, List, Mapping, Optional

from src.trader.execution.allocation_decision import (
    AllocationDecision,
    AllocationDecisionError,
    normalize_allocation_decision,
)


class AllocationDecisionStoreError(RuntimeError):
    """Raised when allocator decision store inputs or rows are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise AllocationDecisionStoreError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise AllocationDecisionStoreError("metadata must be a mapping when provided")
    return dict(value)


def _normalize_path(path: Any) -> Path:
    if isinstance(path, Path):
        return path
    if not isinstance(path, str) or not path.strip():
        raise AllocationDecisionStoreError("store_path must be a non-empty string or Path")
    return Path(path)


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise AllocationDecisionStoreError(f"{name} is required")

    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise AllocationDecisionStoreError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise AllocationDecisionStoreError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise AllocationDecisionStoreError(f"{name} must be mapping-like or expose to_dict()")


@dataclass(frozen=True)
class AllocationDecisionStoreRecord:
    allocation_decision_id: str
    allocator_cycle_id: str
    appended_at_utc: str
    decision: AllocationDecision
    metadata: Dict[str, Any] = field(default_factory=dict)

    def __post_init__(self) -> None:
        object.__setattr__(
            self,
            "allocation_decision_id",
            _require_non_empty_string("allocation_decision_id", self.allocation_decision_id),
        )
        object.__setattr__(
            self,
            "allocator_cycle_id",
            _require_non_empty_string("allocator_cycle_id", self.allocator_cycle_id),
        )
        object.__setattr__(
            self,
            "appended_at_utc",
            _require_non_empty_string("appended_at_utc", self.appended_at_utc),
        )
        normalized_decision = (
            self.decision
            if isinstance(self.decision, AllocationDecision)
            else normalize_allocation_decision(self.decision)
        )
        object.__setattr__(self, "decision", normalized_decision)
        object.__setattr__(self, "metadata", _normalize_metadata(self.metadata))

        if self.allocation_decision_id != normalized_decision.allocation_decision_id:
            raise AllocationDecisionStoreError(
                "allocation_decision_id must match decision.allocation_decision_id"
            )
        if self.allocator_cycle_id != normalized_decision.allocator_cycle_id:
            raise AllocationDecisionStoreError(
                "allocator_cycle_id must match decision.allocator_cycle_id"
            )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocation_decision_id": self.allocation_decision_id,
            "allocator_cycle_id": self.allocator_cycle_id,
            "appended_at_utc": self.appended_at_utc,
            "decision": self.decision.to_dict(),
            "metadata": dict(self.metadata),
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationDecisionStoreRecord":
        if not isinstance(payload, Mapping):
            raise AllocationDecisionStoreError("payload must be a mapping")
        return cls(
            allocation_decision_id=payload.get("allocation_decision_id"),
            allocator_cycle_id=payload.get("allocator_cycle_id"),
            appended_at_utc=payload.get("appended_at_utc"),
            decision=payload.get("decision"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class AllocationDecisionStoreScan:
    store_path: str
    row_count: int
    valid_row_count: int
    invalid_row_count: int
    latest_allocation_decision_id: Optional[str]
    issues: List[str] = field(default_factory=list)

    def to_dict(self) -> Dict[str, Any]:
        return {
            "store_path": self.store_path,
            "row_count": self.row_count,
            "valid_row_count": self.valid_row_count,
            "invalid_row_count": self.invalid_row_count,
            "latest_allocation_decision_id": self.latest_allocation_decision_id,
            "issues": list(self.issues),
        }


def _ensure_parent_directory(path: Path) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)


def append_allocation_decision_record(
    *,
    store_path: Any,
    decision: Any,
    appended_at_utc: Any,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationDecisionStoreRecord:
    normalized_path = _normalize_path(store_path)
    normalized_decision = normalize_allocation_decision(decision)
    normalized_appended_at_utc = _require_non_empty_string("appended_at_utc", appended_at_utc)
    normalized_metadata = dict(metadata or {})

    record = AllocationDecisionStoreRecord(
        allocation_decision_id=normalized_decision.allocation_decision_id,
        allocator_cycle_id=normalized_decision.allocator_cycle_id,
        appended_at_utc=normalized_appended_at_utc,
        decision=normalized_decision,
        metadata=normalized_metadata,
    )

    _ensure_parent_directory(normalized_path)
    with normalized_path.open("a", encoding="utf-8", newline="") as handle:
        handle.write(json.dumps(record.to_dict(), sort_keys=True))
        handle.write("\n")

    return record


def read_allocation_decision_records(
    *,
    store_path: Any,
    strict: bool = True,
) -> List[AllocationDecisionStoreRecord]:
    normalized_path = _normalize_path(store_path)
    if not normalized_path.exists():
        return []

    records: List[AllocationDecisionStoreRecord] = []
    with normalized_path.open("r", encoding="utf-8") as handle:
        for line_number, raw_line in enumerate(handle, start=1):
            line = raw_line.strip()
            if not line:
                continue
            try:
                payload = json.loads(line)
            except json.JSONDecodeError as exc:
                if strict:
                    raise AllocationDecisionStoreError(
                        f"malformed JSON row at line {line_number}"
                    ) from exc
                continue

            try:
                records.append(AllocationDecisionStoreRecord.from_dict(payload))
            except (AllocationDecisionStoreError, AllocationDecisionError) as exc:
                if strict:
                    raise AllocationDecisionStoreError(
                        f"malformed allocation decision row at line {line_number}"
                    ) from exc
                continue

    return records


def get_latest_allocation_decision_record(
    *,
    store_path: Any,
    strict: bool = True,
) -> Optional[AllocationDecisionStoreRecord]:
    records = read_allocation_decision_records(store_path=store_path, strict=strict)
    if not records:
        return None
    return records[-1]


def replay_allocation_decision_by_id(
    *,
    store_path: Any,
    allocation_decision_id: Any,
    strict: bool = True,
) -> AllocationDecisionStoreRecord:
    normalized_allocation_decision_id = _require_non_empty_string(
        "allocation_decision_id",
        allocation_decision_id,
    )
    records = read_allocation_decision_records(store_path=store_path, strict=strict)
    for record in records:
        if record.allocation_decision_id == normalized_allocation_decision_id:
            return record
    raise AllocationDecisionStoreError(
        f"allocation decision not found: {normalized_allocation_decision_id}"
    )


def replay_allocation_decisions_by_cycle(
    *,
    store_path: Any,
    allocator_cycle_id: Any,
    strict: bool = True,
) -> List[AllocationDecisionStoreRecord]:
    normalized_allocator_cycle_id = _require_non_empty_string(
        "allocator_cycle_id",
        allocator_cycle_id,
    )
    records = read_allocation_decision_records(store_path=store_path, strict=strict)
    return [
        record
        for record in records
        if record.allocator_cycle_id == normalized_allocator_cycle_id
    ]


def scan_allocation_decision_store(
    *,
    store_path: Any,
) -> AllocationDecisionStoreScan:
    normalized_path = _normalize_path(store_path)
    if not normalized_path.exists():
        return AllocationDecisionStoreScan(
            store_path=str(normalized_path),
            row_count=0,
            valid_row_count=0,
            invalid_row_count=0,
            latest_allocation_decision_id=None,
            issues=[],
        )

    row_count = 0
    valid_row_count = 0
    invalid_row_count = 0
    latest_allocation_decision_id: Optional[str] = None
    issues: List[str] = []

    with normalized_path.open("r", encoding="utf-8") as handle:
        for line_number, raw_line in enumerate(handle, start=1):
            line = raw_line.strip()
            if not line:
                continue
            row_count += 1
            try:
                payload = json.loads(line)
                record = AllocationDecisionStoreRecord.from_dict(payload)
            except Exception as exc:
                invalid_row_count += 1
                issues.append(f"line {line_number}: {exc}")
                continue

            valid_row_count += 1
            latest_allocation_decision_id = record.allocation_decision_id

    return AllocationDecisionStoreScan(
        store_path=str(normalized_path),
        row_count=row_count,
        valid_row_count=valid_row_count,
        invalid_row_count=invalid_row_count,
        latest_allocation_decision_id=latest_allocation_decision_id,
        issues=issues,
    )
